// ─────────────────────────────────────────────
// MOCK: Simulate what an HTTP node would return
// Replace this block with a real HTTP Request
// node once you're ready to go live.
// ─────────────────────────────────────────────
const USE_MOCK = true; // flip to false for live

const mockApiResponse = {
  users: [
    { id: 1, name: 'Alice',   role: 'admin',  active: true  },
    { id: 2, name: 'Bob',     role: 'viewer', active: false },
    { id: 3, name: 'Charlie', role: 'editor', active: true  }
  ],
  meta: { total: 3, page: 1 }
};

if (USE_MOCK) {
  console.log('[MOCK] Returning fake API response');
  return [{ json: { source: 'mock', data: mockApiResponse } }];
}

// When USE_MOCK = false, connect a real HTTP
// Request node before this Code node instead.

// ─────────────────────────────────────────────
// Process the response — same logic works for
// both mock and real HTTP data
// ─────────────────────────────────────────────
const payload = $json.data;
const users   = payload.users;

const activeUsers = users.filter(u => u.active);
const admins      = users.filter(u => u.role === 'admin');

return [{
  json: {
    totalUsers:   users.length,
    activeUsers:  activeUsers.length,
    adminCount:   admins.length,
    activeNames:  activeUsers.map(u => u.name),
    processedAt:  new Date().toISOString()
  }
}];

// ─────────────────────────────────────────────
// Validate the shape of the processed data
// This acts as your assertion layer
// ─────────────────────────────────────────────
const d = $json;
const errors = [];

if (typeof d.totalUsers !== 'number')  errors.push('totalUsers must be a number');
if (!Array.isArray(d.activeNames))     errors.push('activeNames must be an array');
if (d.activeUsers > d.totalUsers)      errors.push('activeUsers cannot exceed totalUsers');
if (!d.processedAt)                    errors.push('processedAt timestamp missing');

return [{
  json: {
    validationPassed: errors.length === 0,
    errors,
    data: d
  }
}];
